  ('dietitian-moex-10444', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '市場行銷策略常被營養師應用於擬定社區營養計劃，請問市場行銷策略指的4P不包括：', '["product", "promotion", "position", "place"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "c8a56f98cde2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094130", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第二次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
